import chess

def to64(fen):
    out=[]
    for row in fen.split(' ')[0].split('/'):
        for ch in row:
            if ch.isdigit():
                out.append('.'*int(ch))
            else:
                out.append(ch)
    s=''.join(out)
    assert len(s)==64, (len(s), s)
    return s

def compress_row(row):
    res=[]; cnt=0
    for ch in row:
        if ch=='.':
            cnt+=1
        else:
            if cnt:
                res.append(str(cnt)); cnt=0
            res.append(ch)
    if cnt: res.append(str(cnt))
    return ''.join(res)

def from64(s):
    return '/'.join(compress_row(s[i*8:i*8+8]) for i in range(8))

def square_index(sq):
    if sq == '-':
        return None
    file='abcdefgh'.index(sq[0])
    rank=int(sq[1])
    return (8-rank)*8 + file

def gen_pseudo(fen):
    b=chess.Board(fen)
    parts=fen.split(' ')
    board, side, castle, ep = parts[0], parts[1], parts[2], parts[3]
    s=to64(fen)
    moves=[]

    def add_board(ns, castling=castle, ep_out='-'):
        moves.append(from64(''.join(ns)) + f' b {castling} {ep_out} 0 0')

    # Pawns (white moves from higher rank toward lower indices)
    for i,ch in enumerate(s):
        if ch != 'P':
            continue
        r=i//8; f=i%8
        # single step
        if r > 0 and s[i-8] == '.':
            if r == 1:
                ns=list(s); ns[i]='.'; ns[i-8]='Q'; add_board(ns)
            else:
                ns=list(s); ns[i]='.'; ns[i-8]='P'; add_board(ns)
                # double step
                if r == 6 and s[i-16] == '.':
                    ns=list(s); ns[i]='.'; ns[i-16]='P'
                    ep_sq = 'abcdefgh'[f] + '3'
                    add_board(ns, ep_out=ep_sq)
        # captures
        for df in (-1, 1):
            nf = f + df
            if not (0 <= nf < 8):
                continue
            j = i - 8 + df
            if j < 0:
                continue
            target = s[j]
            if target != '.' and target.islower():
                if r == 1:
                    ns=list(s); ns[i]='.'; ns[j]='Q'; add_board(ns)
                else:
                    ns=list(s); ns[i]='.'; ns[j]='P'; add_board(ns)
            # en passant
            epidx = square_index(ep)
            if epidx is not None and j == epidx:
                ns=list(s)
                ns[i]='.'
                ns[j]='P'
                ns[j+8]='.'
                add_board(ns)
    return sorted(set(moves)), b

def legal_set(b):
    out=set()
    for move in b.legal_moves:
        if move.promotion and move.promotion != chess.QUEEN:
            continue
        bb=b.copy(); bb.push(move)
        out.add(' '.join(bb.fen().split(' ')[:4]) + ' 0 0')
    return out

for fen in [
    chess.STARTING_FEN,
    'rnb1k1nr/p2p1ppp/3B4/1p1NPN1P/6P1/3P1Q2/P1P5/q4Kb1 w kq - 0 1',
    'rnbqkbnr/ppp1pppp/8/3pP3/4P3/8/PPPP1PPP/RNBQKBNR w KQkq d6 0 2'
]:
    ms,b=gen_pseudo(fen)
    legal=legal_set(b)
    print('fen', fen)
    print('manual', len(ms), 'legal', len(legal))
    print('missing', sorted(legal-set(ms))[:3])
    print('extra', sorted(set(ms)-legal)[:3])
